{
  "name": "FinOps Pro - Finance Back-Office",
  "description": "A comprehensive finance back-office suite for managing manual refunds, chargebacks, transaction tracking, and ledger resynchronization with intelligent insights powered by Gemini."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ViewType {
  DASHBOARD = 'DASHBOARD',
  MANUAL_REFUND = 'MANUAL_REFUND',
  CHARGEBACK = 'CHARGEBACK',
  RESUBMISSION = 'RESUBMISSION',
  STATUS_CHECK = 'STATUS_CHECK',
  SHADOW_LEDGER = 'SHADOW_LEDGER'
}

export interface TransactionStatus {
  reference: string;
  amount: number;
  status: 'PENDING' | 'COMPLETED' | 'FAILED' | 'REJECTED';
  date: string;
  type: string;
}

export interface ManualRefundData {
  originalRef: string;
  newRef: string;
  amount: number;
  iban: string;
  date: string;
}

export interface ChargebackData {
  originalRef: string;
  amount: number;
  chargebackNumber: string;
  date: string;
  file?: File;
}

import React, { useState } from 'react';
import { 
  LayoutDashboard, 
  RotateCcw, 
  ArrowLeftRight, 
  RefreshCw, 
  Search, 
  Send, 
  Menu, 
  X,
  User,
  Bell
} from 'lucide-react';
import { ViewType } from './types';
import Dashboard from './components/Dashboard';
import ManualRefundForm from './components/ManualRefundForm';
import ChargebackForm from './components/ChargebackForm';
import ResubmissionForm from './components/ResubmissionForm';
import StatusCheck from './components/StatusCheck';
import ShadowLedgerForm from './components/ShadowLedgerForm';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ViewType>(ViewType.DASHBOARD);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  const navigation = [
    { name: 'Dashboard', view: ViewType.DASHBOARD, icon: LayoutDashboard },
    { name: 'Manual Refund', view: ViewType.MANUAL_REFUND, icon: RotateCcw },
    { name: 'Chargebacks', view: ViewType.CHARGEBACK, icon: ArrowLeftRight },
    { name: 'Resubmissions', view: ViewType.RESUBMISSION, icon: RefreshCw },
    { name: 'Status Check', view: ViewType.STATUS_CHECK, icon: Search },
    { name: 'Shadow Ledger', view: ViewType.SHADOW_LEDGER, icon: Send },
  ];

  const renderContent = () => {
    switch (activeView) {
      case ViewType.DASHBOARD: return <Dashboard setActiveView={setActiveView} />;
      case ViewType.MANUAL_REFUND: return <ManualRefundForm />;
      case ViewType.CHARGEBACK: return <ChargebackForm />;
      case ViewType.RESUBMISSION: return <ResubmissionForm />;
      case ViewType.STATUS_CHECK: return <StatusCheck />;
      case ViewType.SHADOW_LEDGER: return <ShadowLedgerForm />;
      default: return <Dashboard setActiveView={setActiveView} />;
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 flex overflow-hidden">
      {/* Sidebar */}
      <aside 
        className={`${
          isSidebarOpen ? 'w-64' : 'w-20'
        } bg-brand-purple text-white transition-all duration-300 flex flex-col z-50`}
      >
        <div className="p-6 flex items-center justify-between">
          {isSidebarOpen ? (
            <span className="text-2xl font-bold tracking-tight text-brand-lime">FinOps Pro</span>
          ) : (
            <span className="text-xl font-bold text-brand-lime">FP</span>
          )}
          <button 
            onClick={() => setIsSidebarOpen(!isSidebarOpen)}
            className="p-1 hover:bg-purple-700 rounded transition-colors"
          >
            {isSidebarOpen ? <X size={20} /> : <Menu size={20} />}
          </button>
        </div>

        <nav className="flex-1 px-4 py-6 space-y-2">
          {navigation.map((item) => (
            <button
              key={item.name}
              onClick={() => setActiveView(item.view)}
              className={`w-full flex items-center space-x-3 p-3 rounded-lg transition-all ${
                activeView === item.view 
                  ? 'bg-brand-lime text-brand-purple font-semibold shadow-lg' 
                  : 'hover:bg-purple-700/50 text-purple-100'
              }`}
            >
              <item.icon size={20} className={activeView === item.view ? 'text-brand-purple' : 'text-purple-300'} />
              {isSidebarOpen && <span>{item.name}</span>}
            </button>
          ))}
        </nav>

        <div className="p-4 border-t border-purple-800">
          <div className="flex items-center space-x-3 text-sm opacity-80">
            <div className="w-8 h-8 rounded-full bg-brand-lime flex items-center justify-center text-brand-purple">
              <User size={16} />
            </div>
            {isSidebarOpen && <span>Finance Admin</span>}
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col h-screen overflow-y-auto">
        <header className="bg-white border-b border-gray-200 h-16 flex items-center justify-between px-8 sticky top-0 z-40">
          <h2 className="text-xl font-semibold text-gray-800">
            {navigation.find(n => n.view === activeView)?.name}
          </h2>
          <div className="flex items-center space-x-4">
            <button className="p-2 text-gray-500 hover:text-brand-purple transition-colors relative">
              <Bell size={20} />
              <span className="absolute top-1 right-1 w-2 h-2 bg-red-500 rounded-full"></span>
            </button>
            <div className="h-6 w-px bg-gray-200 mx-2"></div>
            <div className="flex flex-col items-end">
              <span className="text-sm font-medium text-gray-900 leading-tight">Sarah Jenkins</span>
              <span className="text-xs text-gray-500 italic">Senior Financial Analyst</span>
            </div>
          </div>
        </header>

        <div className="p-8 max-w-7xl mx-auto w-full">
          {renderContent()}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Send, CheckCircle2, AlertCircle } from 'lucide-react';

const ManualRefundForm: React.FC = () => {
  const [formData, setFormData] = useState({
    originalRef: '',
    transactionRef: '',
    amount: '',
    iban: '',
    date: new Date().toISOString().split('T')[0]
  });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [success, setSuccess] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    // Simulate API call
    setTimeout(() => {
      setIsSubmitting(false);
      setSuccess(true);
      setTimeout(() => setSuccess(false), 3000);
    }, 1500);
  };

  return (
    <div className="max-w-2xl mx-auto bg-white p-8 rounded-2xl shadow-sm border border-gray-100">
      <div className="mb-8">
        <h3 className="text-2xl font-bold text-brand-purple">Manual Refund Processing</h3>
        <p className="text-gray-500">Initiate a direct refund back to the customer's bank account.</p>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="space-y-2">
            <label className="text-sm font-semibold text-gray-700">Original Transaction Reference</label>
            <input
              required
              type="text"
              placeholder="e.g. TX-12345"
              className="w-full px-4 py-3 rounded-lg border border-gray-200 focus:ring-2 focus:ring-brand-purple/20 focus:border-brand-purple outline-none transition-all"
              value={formData.originalRef}
              onChange={(e) => setFormData({ ...formData, originalRef: e.target.value })}
            />
          </div>
          <div className="space-y-2">
            <label className="text-sm font-semibold text-gray-700">New Refund Reference</label>
            <input
              required
              type="text"
              placeholder="e.g. RF-98765"
              className="w-full px-4 py-3 rounded-lg border border-gray-200 focus:ring-2 focus:ring-brand-purple/20 focus:border-brand-purple outline-none transition-all"
              value={formData.transactionRef}
              onChange={(e) => setFormData({ ...formData, transactionRef: e.target.value })}
            />
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="space-y-2">
            <label className="text-sm font-semibold text-gray-700">Amount ($)</label>
            <input
              required
              type="number"
              step="0.01"
              placeholder="0.00"
              className="w-full px-4 py-3 rounded-lg border border-gray-200 focus:ring-2 focus:ring-brand-purple/20 focus:border-brand-purple outline-none transition-all"
              value={formData.amount}
              onChange={(e) => setFormData({ ...formData, amount: e.target.value })}
            />
          </div>
          <div className="space-y-2">
            <label className="text-sm font-semibold text-gray-700">Refund Date</label>
            <input
              required
              type="date"
              className="w-full px-4 py-3 rounded-lg border border-gray-200 focus:ring-2 focus:ring-brand-purple/20 focus:border-brand-purple outline-none transition-all"
              value={formData.date}
              onChange={(e) => setFormData({ ...formData, date: e.target.value })}
            />
          </div>
        </div>

        <div className="space-y-2">
          <label className="text-sm font-semibold text-gray-700">IBAN / Account Number</label>
          <input
            required
            type="text"
            placeholder="GB 00 XXXX 0000 0000 0000"
            className="w-full px-4 py-3 rounded-lg border border-gray-200 focus:ring-2 focus:ring-brand-purple/20 focus:border-brand-purple outline-none transition-all font-mono"
            value={formData.iban}
            onChange={(e) => setFormData({ ...formData, iban: e.target.value })}
          />
        </div>

        <div className="pt-4">
          <button
            disabled={isSubmitting}
            type="submit"
            className={`w-full py-4 rounded-xl font-bold flex items-center justify-center space-x-2 transition-all ${
              success 
                ? 'bg-green-500 text-white' 
                : 'bg-brand-purple text-white hover:bg-purple-800 shadow-lg shadow-purple-200'
            } disabled:opacity-50`}
          >
            {isSubmitting ? (
              <span className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></span>
            ) : success ? (
              <>
                <CheckCircle2 size={20} />
                <span>Refund Processed!</span>
              </>
            ) : (
              <>
                <Send size={20} />
                <span>Process Refund</span>
              </>
            )}
          </button>
        </div>
      </form>
    </div>
  );
};

export default ManualRefundForm;

import React, { useState, useRef } from 'react';
import { Upload, FileText, CheckCircle2, X } from 'lucide-react';

const ChargebackForm: React.FC = () => {
  const [formData, setFormData] = useState({
    originalRef: '',
    amount: '',
    chargebackNumber: '',
    date: new Date().toISOString().split('T')[0],
  });
  const [file, setFile] = useState<File | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [success, setSuccess] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    setTimeout(() => {
      setIsSubmitting(false);
      setSuccess(true);
      setTimeout(() => {
        setSuccess(false);
        setFile(null);
        setFormData({
            originalRef: '',
            amount: '',
            chargebackNumber: '',
            date: new Date().toISOString().split('T')[0],
        });
      }, 3000);
    }, 2000);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
    }
  };

  return (
    <div className="max-w-2xl mx-auto bg-white p-8 rounded-2xl shadow-sm border border-gray-100">
      <div className="mb-8">
        <h3 className="text-2xl font-bold text-brand-purple">Report Chargeback</h3>
        <p className="text-gray-500">Record a customer-initiated dispute from the issuing bank.</p>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div className="space-y-2">
          <label className="text-sm font-semibold text-gray-700">Original Transaction Reference</label>
          <input
            required
            type="text"
            className="w-full px-4 py-3 rounded-lg border border-gray-200 focus:ring-2 focus:ring-brand-purple/20 focus:border-brand-purple outline-none transition-all"
            value={formData.originalRef}
            onChange={(e) => setFormData({ ...formData, originalRef: e.target.value })}
          />
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="space-y-2">
            <label className="text-sm font-semibold text-gray-700">Amount ($)</label>
            <input
              required
              type="number"
              step="0.01"
              className="w-full px-4 py-3 rounded-lg border border-gray-200 focus:ring-2 focus:ring-brand-purple/20 focus:border-brand-purple outline-none transition-all"
              value={formData.amount}
              onChange={(e) => setFormData({ ...formData, amount: e.target.value })}
            />
          </div>
          <div className="space-y-2">
            <label className="text-sm font-semibold text-gray-700">Chargeback Number</label>
            <input
              required
              type="text"
              className="w-full px-4 py-3 rounded-lg border border-gray-200 focus:ring-2 focus:ring-brand-purple/20 focus:border-brand-purple outline-none transition-all"
              value={formData.chargebackNumber}
              onChange={(e) => setFormData({ ...formData, chargebackNumber: e.target.value })}
            />
          </div>
        </div>

        <div className="space-y-2">
          <label className="text-sm font-semibold text-gray-700">Dispute Date</label>
          <input
            required
            type="date"
            className="w-full px-4 py-3 rounded-lg border border-gray-200 focus:ring-2 focus:ring-brand-purple/20 focus:border-brand-purple outline-none transition-all"
            value={formData.date}
            onChange={(e) => setFormData({ ...formData, date: e.target.value })}
          />
        </div>

        <div className="space-y-2">
          <label className="text-sm font-semibold text-gray-700">Supporting Document (PDF/Image)</label>
          <div 
            onClick={() => fileInputRef.current?.click()}
            className={`border-2 border-dashed rounded-xl p-8 flex flex-col items-center justify-center cursor-pointer transition-colors ${
              file ? 'border-brand-lime bg-lime-50/30' : 'border-gray-200 hover:border-brand-purple bg-gray-50'
            }`}
          >
            <input 
              type="file" 
              className="hidden" 
              ref={fileInputRef} 
              onChange={handleFileChange}
              accept=".pdf,.png,.jpg,.jpeg"
            />
            {file ? (
              <div className="flex items-center space-x-3 text-brand-purple">
                <FileText size={32} />
                <div className="text-left">
                  <p className="font-semibold text-sm truncate max-w-[200px]">{file.name}</p>
                  <p className="text-xs text-gray-500">{(file.size / 1024).toFixed(1)} KB</p>
                </div>
                <button 
                  onClick={(e) => {
                    e.stopPropagation();
                    setFile(null);
                  }}
                  className="p-1 hover:bg-red-100 rounded-full text-red-500"
                >
                  <X size={16} />
                </button>
              </div>
            ) : (
              <>
                <Upload size={32} className="text-gray-400 mb-2" />
                <p className="text-sm font-medium text-gray-600">Click to upload file or drag & drop</p>
                <p className="text-xs text-gray-400 mt-1">Official bank chargeback notification required</p>
              </>
            )}
          </div>
        </div>

        <button
          disabled={isSubmitting}
          type="submit"
          className={`w-full py-4 rounded-xl font-bold flex items-center justify-center space-x-2 transition-all ${
            success 
              ? 'bg-green-500 text-white' 
              : 'bg-brand-purple text-white hover:bg-purple-800 shadow-lg'
          } disabled:opacity-50`}
        >
          {isSubmitting ? (
            <span className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></span>
          ) : success ? (
            <>
              <CheckCircle2 size={20} />
              <span>Chargeback Logged!</span>
            </>
          ) : (
            <span>Submit Chargeback</span>
          )}
        </button>
      </form>
    </div>
  );
};

export default ChargebackForm;

import React, { useState } from 'react';
import { RefreshCw, CheckCircle2, HelpCircle } from 'lucide-react';

const ResubmissionForm: React.FC = () => {
  const [failedRef, setFailedRef] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [success, setSuccess] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    setTimeout(() => {
      setIsSubmitting(false);
      setSuccess(true);
      setTimeout(() => setSuccess(false), 3000);
    }, 1200);
  };

  return (
    <div className="max-w-2xl mx-auto space-y-6">
      <div className="bg-white p-8 rounded-2xl shadow-sm border border-gray-100">
        <div className="mb-8">
          <h3 className="text-2xl font-bold text-brand-purple">Manual Refund Resubmission</h3>
          <p className="text-gray-500">Retry a previously failed manual refund transaction.</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div className="space-y-2">
            <div className="flex items-center justify-between">
              <label className="text-sm font-semibold text-gray-700">Failed Refund Transaction Reference</label>
              <button type="button" className="text-brand-purple hover:underline text-xs flex items-center">
                <HelpCircle size={14} className="mr-1" /> Find Reference
              </button>
            </div>
            <input
              required
              type="text"
              placeholder="e.g. F-RF-123456"
              className="w-full px-4 py-3 rounded-lg border border-gray-200 focus:ring-2 focus:ring-brand-purple/20 focus:border-brand-purple outline-none transition-all"
              value={failedRef}
              onChange={(e) => setFailedRef(e.target.value)}
            />
          </div>

          <div className="bg-purple-50 p-4 rounded-lg border border-purple-100 flex items-start space-x-3">
            <div className="p-1 mt-0.5">
              <RefreshCw size={16} className="text-brand-purple" />
            </div>
            <p className="text-sm text-brand-purple leading-relaxed">
              <strong>Note:</strong> Resubmitting will generate a new transaction attempt using the existing IBAN details. Ensure the reason for the original failure has been resolved before retrying.
            </p>
          </div>

          <button
            disabled={isSubmitting}
            type="submit"
            className={`w-full py-4 rounded-xl font-bold flex items-center justify-center space-x-2 transition-all ${
              success 
                ? 'bg-green-500 text-white' 
                : 'bg-brand-purple text-white hover:bg-purple-800 shadow-lg'
            } disabled:opacity-50`}
          >
            {isSubmitting ? (
              <span className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></span>
            ) : success ? (
              <>
                <CheckCircle2 size={20} />
                <span>Resubmission Queued!</span>
              </>
            ) : (
              <>
                <RefreshCw size={20} />
                <span>Request Resubmission</span>
              </>
            )}
          </button>
        </form>
      </div>

      <div className="bg-white p-6 rounded-2xl border border-gray-100">
        <h4 className="font-bold text-gray-800 mb-4">Recent Resubmissions</h4>
        <div className="space-y-3">
            {[1, 2, 3].map(i => (
                <div key={i} className="flex items-center justify-between py-2 border-b border-gray-50 last:border-0">
                    <div>
                        <p className="text-sm font-semibold text-gray-800">F-RF-99220{i}</p>
                        <p className="text-xs text-gray-500">Submitted 2 hours ago</p>
                    </div>
                    <span className="px-2 py-1 bg-lime-100 text-brand-purple text-[10px] font-bold rounded uppercase">Processing</span>
                </div>
            ))}
        </div>
      </div>
    </div>
  );
};

export default ResubmissionForm;

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getTransactionInsight = async (transactionData: any) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are a financial operations expert. Analyze the following transaction and provide a concise, professional insight (max 50 words). Transaction: ${JSON.stringify(transactionData)}. Focus on potential risks, status explanation, or recommended next steps for the finance team.`,
      config: {
        temperature: 0.7,
        topK: 40,
        topP: 0.95,
      },
    });

    return response.text;
  } catch (error) {
    console.error('Error getting Gemini insight:', error);
    return "Unable to provide AI insight at this time. Please check manually.";
  }
};

import React, { useState } from 'react';
import { Search, Info, Sparkles, ArrowRight, ShieldCheck, Clock, XCircle } from 'lucide-react';
import { getTransactionInsight } from '../services/geminiService';
import { TransactionStatus } from '../types';

const StatusCheck: React.FC = () => {
  const [ref, setRef] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<TransactionStatus | null>(null);
  const [insight, setInsight] = useState<string | null>(null);

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!ref) return;

    setLoading(true);
    setResult(null);
    setInsight(null);

    // Simulate database lookup
    setTimeout(async () => {
      const mockResult: TransactionStatus = {
        reference: ref,
        amount: Math.floor(Math.random() * 500) + 10,
        status: Math.random() > 0.3 ? 'COMPLETED' : (Math.random() > 0.5 ? 'FAILED' : 'PENDING'),
        date: new Date().toISOString().split('T')[0],
        type: 'Payment'
      };

      setResult(mockResult);
      setLoading(false);

      // Get AI Insight
      const aiInsight = await getTransactionInsight(mockResult);
      setInsight(aiInsight);
    }, 1000);
  };

  const getStatusIcon = (status: string) => {
    switch(status) {
      case 'COMPLETED': return <ShieldCheck className="text-green-500" />;
      case 'PENDING': return <Clock className="text-orange-500" />;
      case 'FAILED': return <XCircle className="text-red-500" />;
      default: return <Info className="text-gray-500" />;
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8">
      <div className="bg-brand-purple p-8 rounded-2xl shadow-xl text-white relative overflow-hidden">
        <div className="relative z-10">
          <h3 className="text-2xl font-bold mb-2">Transaction Status Lookup</h3>
          <p className="text-purple-100 mb-6 opacity-80">Trace and verify transaction lifecycle across all ledgers.</p>

          <form onSubmit={handleSearch} className="relative group">
            <input
              type="text"
              placeholder="Enter Transaction Reference (e.g. TX-48819)..."
              className="w-full bg-white/10 border border-white/20 rounded-xl px-6 py-4 pl-12 focus:bg-white focus:text-gray-900 focus:outline-none focus:ring-4 focus:ring-brand-lime/30 transition-all text-white placeholder-purple-200"
              value={ref}
              onChange={(e) => setRef(e.target.value)}
            />
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-purple-200 group-focus-within:text-gray-400 transition-colors" size={20} />
            <button 
              type="submit"
              className="absolute right-2 top-2 bottom-2 bg-brand-lime text-brand-purple font-bold px-6 rounded-lg hover:scale-105 active:scale-95 transition-transform"
            >
              Search
            </button>
          </form>
        </div>
        <div className="absolute top-0 right-0 p-4 opacity-10">
            <Search size={120} />
        </div>
      </div>

